const CATEGORY_MAP = {
  'Politique': 'POLITICAL', 'Politique internationale': 'POLITICAL', 'Relations internationales': 'POLITICAL',
  'Économie': 'ECONOMIC', 'Géopolitique': 'POLITICAL', 'Droit': 'LEGAL', 'Droit international': 'LEGAL',
  'Société': 'SOCIAL', 'Droits civiques': 'SOCIAL', 'Culture': 'CULTURAL', 'Intellectuel': 'CULTURAL',
  'Militaire': 'MILITARY', 'Religion': 'CULTURAL', 'Médias': 'HGGSP_SPECIFIC',
  'Environnement': 'HGGSP_SPECIFIC', 'Union européenne': 'POLITICAL', 'Mondialisation': 'ECONOMIC',
  'Histoire': 'CULTURAL', 'Histoire antique': 'CULTURAL', 'Histoire coloniale': 'CULTURAL',
  'Histoire française': 'POLITICAL', 'Philosophie': 'CULTURAL', 'Guerre Froide': 'POLITICAL',
  'Résistance': 'MILITARY', 'Géographie': 'GEOGRAPHIC', 'Politique française': 'POLITICAL',
  'Politique antique': 'POLITICAL',
}

export const rawGlossary = [
  // === A ===
  { id: 'gl_absolutisme', term: 'Absolutisme', definition: "Régime politique dans lequel le souverain (roi ou reine) détient tous les pouvoirs sans contrôle ni contrepoids institutionnel. Légitimé par le droit divin. Exemple : la France de Louis XIV. S'oppose à la monarchie constitutionnelle et à la démocratie.", category: 'Politique', level: ['4e', '2nde'], letter: 'A' },
  { id: 'gl_ahimsa', term: 'Ahimsa', definition: "Principe de non-violence dans les traditions indoues, bouddhistes et jaïnes. Gandhi en fait le fondement de sa méthode de résistance passive (satyagraha) contre la domination britannique. Influence directe sur Martin Luther King aux États-Unis.", category: 'Philosophie', level: ['3e', '1ere'], letter: 'A' },
  { id: 'gl_alliance', term: 'Alliance (politique)', definition: "Accord entre États ou groupes politiques visant à coordonner leurs actions. En politique internationale : Triple Alliance (Allemagne, Autriche, Italie) vs Triple Entente (France, Russie, Royaume-Uni) avant 1914. OTAN depuis 1949.", category: 'Politique internationale', level: ['3e', '1ere'], letter: 'A' },
  { id: 'gl_altermondialisme', term: 'Altermondialisme', definition: "Mouvement social international contestant les effets négatifs de la mondialisation néolibérale et proposant 'un autre monde possible'. Né du Forum Social Mondial de Porto Alegre (2001). Critique : inégalités, destruction environnementale, dumping social. Propose : taxe Tobin, commerce équitable.", category: 'Mondialisation', level: ['Terminale', 'HGGSP'], letter: 'A' },
  { id: 'gl_annexion', term: 'Annexion', definition: "Intégration par la force d'un territoire étranger à un État. Exemple : annexion de l'Alsace-Lorraine par l'Allemagne (1871), annexion de la Crimée par la Russie (2014). Contraire à la Charte de l'ONU qui interdit l'acquisition de territoire par la force.", category: 'Géopolitique', level: ['3e', '1ere', 'Terminale'], letter: 'A' },
  { id: 'gl_antisemitisme', term: 'Antisémitisme', definition: "Hostilité, discrimination et persécution à l'égard des Juifs. Fondé sur des préjugés raciaux et religieux. Phénomène ancien (pogroms en Russie tsariste) qui atteint son paroxysme avec le nazisme et la Shoah (1941-1945). Toujours présent aujourd'hui.", category: 'Société', level: ['3e', '1ere'], letter: 'A' },
  { id: 'gl_apartheid', term: 'Apartheid', definition: "Régime de ségrégation raciale institué en Afrique du Sud (1948-1994). Les lois d'apartheid séparent strictement Blancs, Noirs, Colorés et Indiens dans l'espace public, l'éducation, le logement et le travail. L'ANC de Mandela le combat. Fin avec les premières élections multiraciales (1994).", category: 'Droits civiques', level: ['3e', '1ere', 'Terminale'], letter: 'A' },
  { id: 'gl_armistice', term: 'Armistice', definition: "Cessation temporaire des combats par accord entre les belligérants, sans traité de paix définitif. L'armistice du 11 novembre 1918 met fin aux combats de la Première Guerre mondiale. Différent du traité de paix (Versailles, 1919).", category: 'Militaire', level: ['3e', '1ere'], letter: 'A' },
  { id: 'gl_asabiyya', term: 'Asabiyya', definition: "Concept d'Ibn Khaldoun (XIVe s.) désignant la cohésion sociale et la solidarité d'un groupe (tribu, peuple). Pour lui, c'est le moteur de la montée en puissance des civilisations : les peuples nomades à forte asabiyya conquièrent les empires sédentaires affaiblis par le luxe.", category: 'Philosophie', level: ['2nde', 'HGGSP'], letter: 'A' },
  { id: 'gl_autarcie', term: 'Autarcie', definition: "Politique économique visant à l'auto-suffisance totale d'un pays, réduisant au minimum les échanges avec l'extérieur. Pratiquée par l'Allemagne nazie et l'URSS stalinienne. Contraire du libre-échange et de la mondialisation. En Grèce antique, désigne l'idéal d'indépendance de la cité.", category: 'Économie', level: ['3e', '2nde', 'HGGSP'], letter: 'A' },

  // === B ===
  { id: 'gl_brics', term: 'BRICS', definition: "Acronyme désignant le Brésil, la Russie, l'Inde, la Chine, l'Afrique du Sud (South Africa). Inventé par Goldman Sachs en 2001 pour désigner les puissances émergentes. En 2024, s'élargit à l'Iran, EAU, Égypte, Éthiopie. Ils représentent 40% de la population mondiale, 25% du PIB et contestent l'hégémonie occidentale.", category: 'Géopolitique', level: ['Terminale', 'HGGSP'], letter: 'B' },
  { id: 'gl_blocus', term: 'Blocus', definition: "Ensemble de mesures visant à isoler un territoire ennemi en coupant ses voies d'approvisionnement. Blocus continental de Napoléon contre l'Angleterre (1806). Blocus de Berlin (1948-1949) par l'URSS — répondu par le pont aérien américain.", category: 'Militaire', level: ['4e', '3e'], letter: 'B' },
  { id: 'gl_bombe_atomique', term: 'Bombe atomique (nucléaire)', definition: "Arme de destruction massive utilisant la fission nucléaire (uranium 235 ou plutonium). Développée par le Projet Manhattan (USA). Larguée sur Hiroshima (6 août 1945, 70 000-80 000 morts immédiats) et Nagasaki (9 août 1945). La menace nucléaire structure la Guerre Froide (équilibre de la terreur).", category: 'Militaire', level: ['3e', '1ere', 'Terminale'], letter: 'B' },
  { id: 'gl_bulle_de_filtre', term: 'Bulle de filtre (filter bubble)', definition: "Phénomène où les algorithmes des réseaux sociaux enferment l'utilisateur dans des informations correspondant à ses opinions préexistantes, l'isolant des points de vue contraires. Théorisé par Eli Pariser (2011). Contribue à la polarisation politique et au développement du conspirationnisme.", category: 'Médias', level: ['HGGSP'], letter: 'B' },

  // === C ===
  { id: 'gl_capitalisme', term: 'Capitalisme', definition: "Système économique fondé sur la propriété privée des moyens de production, la recherche du profit et le marché libre. Théorisé par Adam Smith (Richesse des nations, 1776). Marx l'analyse et le critique dans Le Capital (1867). Aujourd'hui dominant mondialement, il prend différentes formes (libéral, social-démocrate, autoritaire).", category: 'Économie', level: ['4e', '3e', 'Terminale'], letter: 'C' },
  { id: 'gl_citoyennete', term: 'Citoyenneté', definition: "Appartenance à une communauté politique (cité, nation) qui confère des droits (voter, élire, être élu) et des devoirs (payer les impôts, défendre le pays). En démocratie athénienne, limitée aux hommes libres adultes. Élargie progressivement : abolition de l'esclavage, suffrage universel masculin (1848 en France), suffrage féminin (1944 en France).", category: 'Politique', level: ['6e', '5e', '3e', 'HGGSP'], letter: 'C' },
  { id: 'gl_code_civil', term: 'Code civil', definition: "Corpus de lois régissant les relations entre particuliers (propriété, contrats, famille, successions). Le Code civil napoléonien (1804) unifie le droit français et reste fondateur du droit français actuel. Exporté dans toute l'Europe napoléonienne et dans les anciennes colonies françaises.", category: 'Droit', level: ['4e', '3e'], letter: 'C' },
  { id: 'gl_colonialisme', term: 'Colonialisme', definition: "Politique d'un État qui étend son autorité politique et économique sur des territoires et des populations étrangers. Légitimé au XIXe s. par la 'mission civilisatrice'. La conférence de Berlin (1884-1885) partage l'Afrique entre puissances européennes. Génère des résistances (anticolonialisme) et aboutit aux indépendances (1945-1980).", category: 'Histoire coloniale', level: ['4e', '3e', '1ere', 'Terminale'], letter: 'C' },
  { id: 'gl_communisme', term: 'Communisme', definition: "Idéologie politique et économique fondée sur la propriété collective des moyens de production, l'abolition des classes sociales et de la propriété privée. Théorisé par Marx et Engels. Mis en pratique par Lénine en URSS (1917), puis Mao en Chine (1949), Castro à Cuba (1959). Effondrement des régimes communistes soviétiques en 1989-1991.", category: 'Politique', level: ['3e', 'Terminale'], letter: 'C' },
  { id: 'gl_containment', term: 'Containment (endiguement)', definition: "Stratégie américaine de la Guerre Froide visant à empêcher l'expansion du communisme soviétique sans l'attaquer directement. Théorisée par George Kennan (1946), annoncée par la doctrine Truman (1947). Concrétisée par le Plan Marshall, l'OTAN, la guerre de Corée, le Vietnam.", category: 'Géopolitique', level: ['3e', 'Terminale'], letter: 'C' },
  { id: 'gl_cop', term: 'COP (Conference of the Parties)', definition: "Réunion annuelle des États signataires de la Convention-cadre de l'ONU sur les changements climatiques (CCNUCC). La COP21 (Paris, 2015) produit l'Accord de Paris (limiter le réchauffement à +1,5-2°C). La COP27 (Charm el-Cheikh, 2022) crée le fonds 'pertes et dommages' pour les pays vulnérables.", category: 'Environnement', level: ['Terminale', 'HGGSP'], letter: 'C' },
  { id: 'gl_croissance', term: 'Croissance économique', definition: "Augmentation durable de la production de biens et services d'une économie, mesurée par l'évolution du PIB (Produit Intérieur Brut). Les Trente Glorieuses (1945-1973) voient une croissance de 5% par an en France. La crise de 1973 puis de 2008 ralentissent la croissance. Débat : croissance vs décroissance face aux limites écologiques.", category: 'Économie', level: ['3e', '4e', 'Terminale'], letter: 'C' },

  // === D ===
  { id: 'gl_decolonisation', term: 'Décolonisation', definition: "Processus par lequel les peuples colonisés accèdent à l'indépendance politique. Accéléré après 1945 (Charte de l'ONU, affaiblissement des puissances européennes). Deux voies : négociée (Maroc, Tunisie 1956) ou après guerre (Algérie 1962, Indochine 1954). La Conférence de Bandung (1955) fédère les États décolonisés.", category: 'Histoire coloniale', level: ['3e', '1ere', 'Terminale'], letter: 'D' },
  { id: 'gl_democratie', term: 'Démocratie', definition: "Régime politique dans lequel la souveraineté appartient au peuple (demos = peuple, kratos = pouvoir). Elle peut être directe (Athènes, -Ve s.) ou représentative (élus représentent le peuple). Elle implique : suffrage universel, pluralisme politique, liberté de presse, état de droit, séparation des pouvoirs. Aujourd'hui, 55% des États sont considérés comme des démocraties (Freedom House).", category: 'Politique', level: ['6e', '3e', 'Terminale', 'HGGSP'], letter: 'D' },
  { id: 'gl_dev_durable', term: 'Développement durable', definition: "Développement qui répond aux besoins du présent sans compromettre la capacité des générations futures à répondre aux leurs (Rapport Brundtland, 1987). Il repose sur 3 piliers : économique (croissance), social (équité), environnemental (préservation). Concrétisé par les ODD (Objectifs de Développement Durable, ONU, 2015).", category: 'Environnement', level: ['3e', 'Terminale', 'HGGSP'], letter: 'D' },
  { id: 'gl_diktat', term: 'Diktat', definition: "Terme allemand désignant une décision imposée par le plus fort sans négociation. Les Allemands qualifient le traité de Versailles (1919) de 'diktat' car ils sont exclus des négociations et doivent signer sans pouvoir discuter les clauses. Ce ressenti d'humiliation contribue à la montée du nazisme.", category: 'Diplomatie', level: ['3e', '1ere'], letter: 'D' },
  { id: 'gl_diplomatie', term: 'Diplomatie', definition: "Art et pratique de la négociation entre États pour régler les différends sans recourir à la guerre. Elle s'exerce via les ambassadeurs, les traités, les organisations internationales (ONU). La 'diplomatie secrète' (critiquée par Wilson) s'oppose à la 'diplomatie ouverte'. La diplomatie économique (aide au développement, traités commerciaux) est un outil de soft power.", category: 'Relations internationales', level: ['3e', 'Terminale', 'HGGSP'], letter: 'D' },
  { id: 'gl_droit_divin', term: 'Droit divin', definition: "Théorie selon laquelle le pouvoir du roi vient directement de Dieu. Le roi n'est responsable que devant Dieu, pas devant ses sujets. Fondement théologique de la monarchie absolue (Louis XIV). Contesté par les philosophes des Lumières (Locke, Rousseau) qui fondent le pouvoir sur le contrat social.", category: 'Politique', level: ['5e', '4e', '2nde'], letter: 'D' },

  // === E ===
  { id: 'gl_economie_marche', term: 'Économie de marché', definition: "Système dans lequel la production et la distribution des biens sont déterminées par l'offre et la demande, et non par l'État. S'oppose à l'économie planifiée (URSS). Les Trente Glorieuses sont fondées sur une économie de marché régulée par l'État providence (keynésianisme). La mondialisation néolibérale pousse à la déréglementation.", category: 'Économie', level: ['3e', 'Terminale', 'HGGSP'], letter: 'E' },
  { id: 'gl_empire', term: 'Empire', definition: "Ensemble de territoires et de peuples soumis à l'autorité d'un même souverain (empereur). Différent du royaume par son étendue et sa diversité. Exemples : Empire romain, Empire ottoman, Empire colonial britannique. Les empires coloniaux européens du XIXe s. dominent 25% de la surface terrestre.", category: 'Politique', level: ['6e', '5e', '4e', '3e'], letter: 'E' },
  { id: 'gl_etat_de_droit', term: 'État de droit', definition: "Principe selon lequel l'État lui-même est soumis au droit et ne peut agir que dans le cadre fixé par la constitution et les lois. Les individus sont protégés contre l'arbitraire du pouvoir par des recours juridiques (tribunaux indépendants). Opposé au régime autoritaire où le pouvoir est au-dessus des lois.", category: 'Droit', level: ['3e', 'Terminale', 'HGGSP'], letter: 'E' },
  { id: 'gl_ethnie', term: 'Ethnie', definition: "Groupe humain partageant une culture, une langue, une histoire et éventuellement une religion communes. Différent de la race (catégorie biologique rejetée par les scientifiques). Les conflits ethniques (Rwanda 1994, ex-Yougoslavie) impliquent des violences entre groupes ethniques différents au sein d'un même État.", category: 'Société', level: ['3e', '1ere', 'Terminale'], letter: 'E' },
  { id: 'gl_extremisme', term: 'Extrémisme', definition: "Position politique, religieuse ou idéologique radicale, rejetant le compromis et la démocratie. L'extrémisme violent peut conduire au terrorisme. L'extrémisme de droite (nationalisme, fascisme) et l'extrémisme islamiste sont les principales menaces actuelles. Se distingue du radicalisme (pensée radicale mais pas nécessairement violente).", category: 'Politique', level: ['3e', 'Terminale', 'HGGSP'], letter: 'E' },

  // === F ===
  { id: 'gl_fake_news', term: 'Fake news (infox)', definition: "Information délibérément fausse ou trompeuse diffusée comme si elle était vraie, souvent via les réseaux sociaux. Se répand grâce aux émotions (indignation, peur) et aux algorithmes. Peut influencer des élections (2016 USA, Brexit), alimenter la défiance envers les institutions et les experts.", category: 'Médias', level: ['HGGSP'], letter: 'F' },
  { id: 'gl_fascisme', term: 'Fascisme', definition: "Régime politique totalitaire fondé par Mussolini en Italie (1922). Caractérisé par : nationalisme exacerbé, culte du chef (Duce, Führer), corporatisme, violence politique, anti-communisme. S'oppose au libéralisme et au communisme. Le nazisme allemand est une forme extrême de fascisme + racisme + antisémitisme.", category: 'Politique', level: ['3e', '1ere'], letter: 'F' },
  { id: 'gl_ftn', term: 'Firme Transnationale (FTN)', definition: "Entreprise qui organise sa production et ses activités dans plusieurs pays pour maximiser ses profits. Elle dissocie R&D (pays riches), production (pays à bas coûts) et siège social (paradis fiscal). Apple, Samsung, Total, Toyota sont des FTN. Elles contrôlent 2/3 du commerce mondial et peuvent échapper aux régulations nationales.", category: 'Économie', level: ['Terminale', 'HGGSP'], letter: 'F' },
  { id: 'gl_front_populaire', term: 'Front Populaire', definition: "Coalition des partis de gauche français (SFIO, Parti Radical, PCF) qui gagne les élections de mai 1936 sous la direction de Léon Blum. Accords Matignon : semaine de 40h, congés payés, liberté syndicale. Première expérience gouvernementale de gauche en France. Dissous en 1938.", category: 'Politique française', level: ['3e', '1ere'], letter: 'F' },

  // === G ===
  { id: 'gl_genocide', term: 'Génocide', definition: "Destruction intentionnelle et systématique d'un groupe ethnique, racial ou religieux. Terme inventé par Raphael Lemkin (1944). La Convention ONU (1948) le criminalise. Exemples : Shoah (6 millions de Juifs, 1941-1945), génocide arménien (1,5 million, 1915-1916), génocide des Tutsi au Rwanda (800 000, 1994).", category: 'Droit international', level: ['3e', '1ere', 'Terminale'], letter: 'G' },
  { id: 'gl_geopolitique', term: 'Géopolitique', definition: "Étude des relations entre la géographie et la politique internationale : comment les frontières, les ressources naturelles, la topographie et la démographie influencent les rapports de force entre États. Yves Lacoste fonde la revue Hérodote (1976). La géopolitique analyse les conflits, les alliances et les zones d'influence.", category: 'Relations internationales', level: ['Terminale', 'HGGSP'], letter: 'G' },
  { id: 'gl_giec', term: 'GIEC', definition: "Groupe d'Experts Intergouvernemental sur l'Évolution du Climat (1988). Il synthétise les recherches scientifiques mondiales sur le climat. Ses rapports font consensus : le réchauffement est réel (+1,1°C depuis 1850), d'origine humaine (CO2), et ses effets seront catastrophiques au-delà de +1,5-2°C. Prix Nobel de la Paix partagé en 2007.", category: 'Environnement', level: ['Terminale', 'HGGSP'], letter: 'G' },
  { id: 'gl_glasnost', term: 'Glasnost', definition: "Politique de transparence et d'ouverture lancée par Gorbatchev en URSS dès 1986. Elle permet la liberté de presse, la publication d'informations sur les crimes du passé soviétique (Goulag, purges) et favorise le débat public. Avec la perestroïka, elle contribue à l'effondrement de l'URSS.", category: 'Politique', level: ['3e', 'Terminale'], letter: 'G' },
  { id: 'gl_goulag', term: 'Goulag', definition: "Réseau de camps de travail forcé soviétiques sous Staline. Plus de 18 millions de personnes y sont passées entre 1930 et 1953. Les détenus (dissidents, minorités, prisonniers de guerre) sont exploités dans des conditions inhumaines en Sibérie. Alexandre Soljenitsyne l'a révélé au monde (L'Archipel du Goulag, 1973).", category: 'Histoire', level: ['3e', '1ere'], letter: 'G' },
  { id: 'gl_guerre_froide', term: 'Guerre Froide', definition: "Période de rivalité politique, idéologique et militaire entre les États-Unis et l'URSS (1947-1991) sans affrontement direct (d'où 'froide'). Elle se manifeste par : course aux armements nucléaires, guerres par procuration (Corée, Vietnam), blocus, propagande. Fin avec la chute de l'URSS (1991).", category: 'Histoire', level: ['3e', 'Terminale'], letter: 'G' },
  { id: 'gl_guerre_totale', term: 'Guerre totale', definition: "Conflit mobilisant toutes les ressources d'une société : économie, démographie, idéologie. La frontière combattants/civils s'efface. Apparu lors de la Première Guerre mondiale (blocus maritime, mobilisation industrielle) et atteint son sommet pendant la Seconde (bombardements de civils, Shoah).", category: 'Militaire', level: ['3e', '1ere'], letter: 'G' },

  // === H ===
  { id: 'gl_hard_power', term: 'Hard power', definition: "Capacité d'un État à obtenir ce qu'il veut par la contrainte : force militaire (armée, armes nucléaires) ou pression économique (sanctions, embargos). S'oppose au soft power. Concept de Joseph Nye (1990). Les États-Unis, la Chine et la Russie sont les principales puissances de hard power.", category: 'Relations internationales', level: ['Terminale', 'HGGSP'], letter: 'H' },
  { id: 'gl_hegire', term: 'Hégire', definition: "Migration du prophète Muhammad de La Mecque à Médine en 622 après J.-C. C'est l'an 1 du calendrier musulman (calendrier hégirien, lunaire). Événement fondateur de l'Islam comme religion politique. La communauté des croyants (umma) se constitue à Médine.", category: 'Religion', level: ['5e'], letter: 'H' },
  { id: 'gl_hegemonie', term: 'Hégémonie', definition: "Domination d'un État, d'une civilisation ou d'un groupe sur les autres. En géopolitique : puissance hégémonique qui impose ses normes, ses valeurs et ses intérêts. Les États-Unis exercent une hégémonie mondiale depuis 1991 (soft et hard power). La montée de la Chine conteste cette hégémonie.", category: 'Relations internationales', level: ['Terminale', 'HGGSP'], letter: 'H' },
  { id: 'gl_holdomor', term: 'Holodomor', definition: "Famine organisée en Ukraine par Staline (1932-1933). 4 à 7 millions d'Ukrainiens meurent de faim. Résulte de la collectivisation forcée et de la volonté de briser la résistance ukrainienne. Reconnu comme génocide par de nombreux États. Traumatisme fondateur de l'identité nationale ukrainienne moderne.", category: 'Histoire', level: ['3e', '1ere'], letter: 'H' },
  { id: 'gl_humanisme', term: 'Humanisme', definition: "Courant intellectuel et littéraire de la Renaissance (XVe-XVIe s.) qui place l'homme au centre de toutes préoccupations et redécouvre les textes de l'Antiquité greco-romaine. Figures : Érasme, Rabelais, Montaigne. Précurseur des Lumières et du libéralisme politique.", category: 'Intellectuel', level: ['5e', '2nde'], letter: 'H' },
  { id: 'gl_hyperpuissance', term: 'Hyperpuissance', definition: "Expression utilisée par Hubert Védrine (ministre français des AE) en 1998 pour désigner la position unique des États-Unis après la fin de la Guerre Froide. Seul État dominant militairement, économiquement et culturellement. Le 'moment unipolaire' (Krauthammer, 1990). Remis en cause par la montée de la Chine et l'enlisement en Irak.", category: 'Relations internationales', level: ['Terminale', 'HGGSP'], letter: 'H' },

  // === I ===
  { id: 'gl_ideologie', term: 'Idéologie', definition: "Ensemble cohérent d'idées, de valeurs et de croyances qui guide l'action politique d'un groupe ou d'un régime. Principales idéologies modernes : libéralisme, socialisme, communisme, fascisme, nationalisme, islamisme. Marx analyse les idéologies comme des outils de domination de classe.", category: 'Politique', level: ['3e', '1ere', 'Terminale'], letter: 'I' },
  { id: 'gl_imperialisme', term: 'Impérialisme', definition: "Politique d'expansion d'un État visant à dominer d'autres peuples par la force militaire, économique ou culturelle. L'impérialisme européen du XIXe s. aboutit à la colonisation de l'Afrique et de l'Asie. Lénine (L'Impérialisme, stade suprême du capitalisme, 1917) analyse l'impérialisme comme une conséquence du capitalisme financier.", category: 'Histoire', level: ['4e', '3e', '1ere'], letter: 'I' },
  { id: 'gl_islamophobie', term: 'Islamophobie', definition: "Hostilité, discrimination et préjugés à l'encontre de l'islam et des musulmans. Le terme est débattu : pour certains, il désigne une forme de racisme ; pour d'autres, il risque de confondre critique de la religion et discrimination envers les personnes. En France, les actes islamophobes (agressions, profanations) sont recensés par le CNCDH. Enjeu central des débats sur la laïcité et le vivre-ensemble.", category: 'Société', level: ['3e', 'Terminale', 'HGGSP'], letter: 'I' },
  { id: 'gl_isolationnisme', term: 'Isolationnisme', definition: "Politique étrangère d'un État qui refuse de s'engager dans les affaires internationales. Tradition américaine entre les deux guerres (refus de rejoindre la SDN, neutralité jusqu'à Pearl Harbor). Remis en cause depuis 1945 mais toujours présent dans la rhétorique (Trump, 'America First').", category: 'Relations internationales', level: ['Terminale', 'HGGSP'], letter: 'I' },

  // === L ===
  { id: 'gl_laicite', term: 'Laïcité', definition: "Principe de séparation des Églises et de l'État, garantissant la neutralité de l'État en matière religieuse et la liberté de conscience des individus. En France : loi de séparation de l'Église et de l'État (1905). Les agents de l'État et les élèves dans les écoles publiques ne peuvent afficher de signes religieux ostensibles.", category: 'Société', level: ['3e', '1ere', 'HGGSP'], letter: 'L' },
  { id: 'gl_liberalisme', term: 'Libéralisme', definition: "Courant politique et économique défendant les libertés individuelles (Locke, Montesquieu), la limitation du pouvoir de l'État, la séparation des pouvoirs et le libre-échange (Adam Smith). Libéralisme politique (démocratie, droits de l'homme) ≠ libéralisme économique (marché libre, dérégulation).", category: 'Politique', level: ['4e', '3e', '2nde', 'Terminale'], letter: 'L' },
  { id: 'gl_lumieres', term: 'Lumières', definition: "Mouvement intellectuel européen du XVIIIe siècle qui défend la raison, la liberté et le progrès contre l'obscurantisme religieux et l'absolutisme. Figures : Voltaire, Rousseau, Montesquieu, Diderot, Kant. L'Encyclopédie (1751-1772) diffuse ces idées. Influence directe sur les révolutions américaine et française.", category: 'Intellectuel', level: ['4e', '2nde'], letter: 'L' },

  // === M ===
  { id: 'gl_maquis', term: 'Maquis (Résistance)', definition: "Terme désignant les groupes armés de la Résistance française cachés dans les régions isolées (Vercors, Glières). Le 'maquis' s'oppose à la résistance urbaine (réseaux). Il mène des sabotages, renseigne les Alliés, s'oppose aux occupants allemands et à la Milice de Vichy.", category: 'Résistance', level: ['3e', '1ere'], letter: 'M' },
  { id: 'gl_memoire', term: 'Mémoire historique', definition: "Façon dont une société se souvient et interprète son passé. La mémoire collective peut être officielle (commémorations, musées) ou individuelle (témoignages). Elle est soumise à des conflits (guerre des mémoires) : la Shoah, l'esclavage, la colonisation font l'objet de mémoires disputées entre groupes sociaux.", category: 'Histoire', level: ['3e', '1ere', 'Terminale', 'HGGSP'], letter: 'M' },
  { id: 'gl_mondialisation', term: 'Mondialisation', definition: "Intensification des échanges mondiaux de biens, services, capitaux, personnes et idées, accélérée depuis les années 1990 par Internet, les transports et la libéralisation commerciale (OMC). Elle réduit la pauvreté en Asie mais accentue les inégalités entre pays riches et pauvres et dans les pays développés.", category: 'Économie', level: ['3e', 'Terminale', 'HGGSP'], letter: 'M' },
  { id: 'gl_multipolaire', term: 'Multipolarité', definition: "Système international dans lequel plusieurs États exercent une influence comparable, s'équilibrant mutuellement. Opposé à l'unipolarité (un seul dominant : les USA après 1991) et à la bipolarité (deux blocs : Guerre Froide). Avec la montée des BRICS, le monde devient progressivement multipolaire.", category: 'Relations internationales', level: ['Terminale', 'HGGSP'], letter: 'M' },

  // === N ===
  { id: 'gl_nationalisme', term: 'Nationalisme', definition: "Idéologie qui place la nation au-dessus de tout et revendique l'autodétermination des peuples. Peut être libérateur (mouvements d'indépendance, Grèce 1821, Allemagne 1848) ou agressif (pangermanisme, nazisme). Au XIXe s., le nationalisme favorise la construction d'États-nations en Europe.", category: 'Politique', level: ['4e', '3e', '1ere', 'Terminale'], letter: 'N' },
  { id: 'gl_nakba', term: 'Nakba', definition: "'Catastrophe' en arabe. Désigne l'exode forcé de 700 000 Palestiniens lors de la guerre de 1948 et la création d'Israël. Leurs descendants (5-6 millions) vivent dans des camps en Jordanie, Liban, Gaza, Cisjordanie. La Nakba est un traumatisme fondateur de l'identité palestinienne.", category: 'Géopolitique', level: ['Terminale', 'HGGSP'], letter: 'N' },
  { id: 'gl_nazisme', term: 'Nazisme', definition: "Idéologie politique du parti national-socialiste (NSDAP) d'Hitler. Fondée sur : racisme biologique (antisémitisme, hiérarchie des races), ultranationalisme allemand, anticommunisme, pangermanisme (espace vital / Lebensraum). Régime totalitaire de 1933 à 1945. Crime contre l'humanité : la Shoah.", category: 'Politique', level: ['3e', '1ere'], letter: 'N' },
  { id: 'gl_non_aligne', term: 'Non-alignement', definition: "Mouvement de pays refusant d'appartenir aux blocs américain ou soviétique pendant la Guerre Froide. Fondé à la Conférence de Bandung (1955) par Nehru (Inde), Nasser (Égypte), Tito (Yougoslavie). Aujourd'hui, l'Inde pratique un 'non-alignement actif' face à la rivalité USA-Chine.", category: 'Relations internationales', level: ['3e', 'Terminale', 'HGGSP'], letter: 'N' },

  // === O ===
  { id: 'gl_otan', term: 'OTAN', definition: "Organisation du Traité de l'Atlantique Nord (1949). Alliance militaire défensive entre les USA et les démocraties occidentales contre l'URSS. Article 5 : attaque contre un membre = attaque contre tous. Après 1991, s'élargit à l'Europe de l'Est (anciens pays communistes). La guerre en Ukraine (2022) la renforce.", category: 'Relations internationales', level: ['3e', 'Terminale'], letter: 'O' },
  { id: 'gl_onu', term: 'ONU (Organisation des Nations Unies)', definition: "Organisation internationale fondée en 1945 par la Charte de San Francisco. 193 États membres. Principales institutions : Assemblée générale (tous les États), Conseil de Sécurité (5 membres permanents avec droit de veto : USA, Russie, Chine, UK, France). Objectifs : paix, sécurité collective, droits de l'homme, développement.", category: 'Relations internationales', level: ['3e', 'Terminale', 'HGGSP'], letter: 'O' },
  { id: 'gl_ostracisme', term: 'Ostracisme', definition: "Procédure athénienne par laquelle les citoyens votaient pour exiler pendant 10 ans (sans perdre ses biens) une personne jugée dangereuse pour la démocratie. Vote avec des tessons de poterie (ostrakon). Mécanisme préventif contre la tyrannie. Thémistocle, Aristide et Cimon en furent victimes.", category: 'Politique antique', level: ['6e', 'HGGSP'], letter: 'O' },

  // === P ===
  { id: 'gl_panafricanisme', term: 'Panafricanisme', definition: "Mouvement politique et culturel prônant l'unité et la solidarité de tous les peuples africains, y compris la diaspora africaine dans les Amériques. Figures : Kwame Nkrumah (Ghana), Patrice Lumumba (Congo), Aimé Césaire. L'Union Africaine (2002) en est l'héritière institutionnelle.", category: 'Histoire coloniale', level: ['3e', '1ere', 'Terminale'], letter: 'P' },
  { id: 'gl_parlement_eu', term: 'Parlement européen', definition: "Institution de l'Union européenne élue au suffrage universel direct depuis 1979. Ses 705 membres (eurodéputés) représentent les 450 millions de citoyens européens. Il vote les lois européennes (avec le Conseil de l'UE) et contrôle la Commission. Siège à Strasbourg (France).", category: 'Union européenne', level: ['3e', 'Terminale'], letter: 'P' },
  { id: 'gl_patrimoine', term: 'Patrimoine', definition: "Ensemble de biens hérités du passé (matériels : monuments, sites archéologiques ; immatériels : langues, musiques, traditions) qui fondent l'identité d'une société. L'UNESCO classe le patrimoine mondial depuis 1972 (1 199 sites). Sa protection est un enjeu géopolitique (restitutions, destructions volontaires).", category: 'Culture', level: ['HGGSP'], letter: 'P' },
  { id: 'gl_pax_romana', term: 'Pax Romana', definition: "Période de relative paix et de prospérité dans l'Empire romain (27 av. J.-C. - 180 ap. J.-C.). Elle commence avec le règne d'Auguste et couvre l'apogée de l'Empire. Caractérisée par : stabilité politique, essor du commerce, romanisation des provinces, développement des arts.", category: 'Histoire antique', level: ['6e', '2nde'], letter: 'P' },
  { id: 'gl_perestroika', term: 'Perestroïka', definition: "Politique de 'restructuration' économique lancée par Gorbatchev en URSS (1985-1991). Elle vise à rendre l'économie soviétique plus efficace par une décentralisation et l'introduction d'éléments de marché. Elle génère des pénuries et des désordres qui, avec la glasnost, contribuent à l'effondrement de l'URSS.", category: 'Politique', level: ['3e', 'Terminale'], letter: 'P' },
  { id: 'gl_petrole', term: 'Pétrole', definition: "Ressource énergétique fossile, principal carburant de l'économie mondiale depuis le XXe siècle. Sa répartition inégale (50% des réserves au Moyen-Orient) génère des tensions géopolitiques. L'OPEP (1960) régule la production. Les chocs pétroliers (1973, 1979) révèlent la dépendance des pays industrialisés.", category: 'Économie', level: ['Terminale', 'HGGSP'], letter: 'P' },
  { id: 'gl_pillars_islam', term: 'Piliers de l\'islam', definition: "Les 5 obligations fondamentales de l'islam : 1) Shahada (profession de foi) ; 2) Salat (5 prières quotidiennes) ; 3) Zakat (aumône légale) ; 4) Sawm (jeûne du Ramadan) ; 5) Hajj (pèlerinage à La Mecque au moins une fois dans sa vie si on en a les moyens).", category: 'Religion', level: ['5e'], letter: 'P' },
  { id: 'gl_populisme', term: 'Populisme', definition: "Courant politique qui oppose 'le peuple pur' à 'une élite corrompue' et se présente comme l'unique représentant du peuple. Peut être de gauche (Chávez, Mélenchon) ou de droite (Trump, Le Pen, Orban). Il rejette les corps intermédiaires (partis, syndicats, médias) et favorise la relation directe entre le leader et 'le peuple'.", category: 'Politique', level: ['Terminale', 'HGGSP'], letter: 'P' },
  { id: 'gl_propaganda', term: 'Propagande', definition: "Technique de communication visant à influencer l'opinion publique de manière non-critique par la répétition, la simplification et la manipulation émotionnelle. Les régimes totalitaires (Goebbels, ministère de la Propagande nazie ; Agitprop soviétique) en font un instrument central de pouvoir.", category: 'Politique', level: ['3e', '1ere', 'HGGSP'], letter: 'P' },

  // === R ===
  { id: 'gl_reforme', term: 'Réforme protestante', definition: "Mouvement religieux initié par Martin Luther (1517, thèses de Wittenberg) contestant les abus de l'Église catholique (vente des indulgences, enrichissement du clergé). Luther, Calvin et Zwingli fondent différentes Églises protestantes. La Réforme divise définitivement le christianisme occidental.", category: 'Religion', level: ['5e', '2nde'], letter: 'R' },
  { id: 'gl_regime_vichy', term: 'Régime de Vichy', definition: "Gouvernement français dirigé par le maréchal Pétain (juillet 1940 - août 1944) après la défaite et l'armistice avec l'Allemagne. La 'Révolution nationale' remplace 'Liberté, Égalité, Fraternité' par 'Travail, Famille, Patrie'. Vichy collabore activement avec l'Occupant nazi, notamment dans la déportation des Juifs.", category: 'Histoire française', level: ['3e', '1ere'], letter: 'R' },
  { id: 'gl_revolution_industrielle', term: 'Révolution industrielle', definition: "Transformation majeure des modes de production caractérisée par la mécanisation (machine à vapeur), l'essor de l'industrie, l'urbanisation et l'émergence du prolétariat. Née en Angleterre dans la 2e moitié du XVIIIe s., elle se diffuse en Europe et en Amérique au XIXe s. Elle crée le capitalisme industriel et le mouvement ouvrier.", category: 'Économie', level: ['4e', '3e'], letter: 'R' },
  { id: 'gl_rideau_fer', term: 'Rideau de fer', definition: "Expression popularisée par Churchill (discours de Fulton, 5 mars 1946) pour désigner la frontière idéologique et physique divisant l'Europe en deux blocs (Ouest libéral vs Est communiste). Cette ligne va de Stettin (Pologne) à Trieste (Italie). Le mur de Berlin en est la manifestation la plus concrète.", category: 'Guerre Froide', level: ['3e', 'Terminale'], letter: 'R' },
  { id: 'gl_romanisation', term: 'Romanisation', definition: "Processus par lequel les peuples conquis par Rome adoptent progressivement la langue, la culture, les institutions et le mode de vie romain. Les élites locales sont les premières romanisées. Elle passe par les légions, les villes (forum, thermes, amphithéâtre), le droit romain et la citoyenneté.", category: 'Histoire antique', level: ['6e', '2nde'], letter: 'R' },

  // === S ===
  { id: 'gl_sdh', term: 'SDN (Société des Nations)', definition: "Organisation internationale fondée par le traité de Versailles (1919) sur l'initiative de Wilson. Premier projet de sécurité collective mondiale. Elle est affaiblie car les USA (Sénat refuse) n'en font pas partie. Incapable de s'opposer aux agressions des années 1930 (Japon, Italie, Allemagne). Remplacée par l'ONU en 1945.", category: 'Relations internationales', level: ['3e', '1ere'], letter: 'S' },
  { id: 'gl_shoah', term: 'Shoah', definition: "'Catastrophe' en hébreu. Désigne l'extermination systématique de 6 millions de Juifs d'Europe par le régime nazi (1941-1945). La 'Solution finale' (Wannsee, janvier 1942) organise les camps d'extermination (Auschwitz-Birkenau, Treblinka, Sobibor). Événement fondateur de la mémoire juive contemporaine et du droit international (CPI, génocide).", category: 'Histoire', level: ['3e', '1ere', 'Terminale'], letter: 'S' },
  { id: 'gl_soft_power', term: 'Soft power', definition: "Capacité d'un État à obtenir ce qu'il veut par l'attraction et la persuasion plutôt que par la contrainte (hard power). Concept de Joseph Nye (1990). Se manifeste par : rayonnement culturel (Hollywood, K-pop), attractivité des universités, diplomatie d'influence, aide au développement, normes internationales.", category: 'Relations internationales', level: ['Terminale', 'HGGSP'], letter: 'S' },
  { id: 'gl_souverainete', term: 'Souveraineté', definition: "Principe selon lequel un État exerce un pouvoir suprême et exclusif sur son territoire et sa population, sans ingérence extérieure. Concept de Jean Bodin (XVIe s.). La Charte de l'ONU (1945) consacre l'égalité souveraine des États. La mondialisation et les organisations supranationales (UE) la mettent en question.", category: 'Droit', level: ['3e', 'Terminale', 'HGGSP'], letter: 'S' },
  { id: 'gl_subsidiarite', term: 'Subsidiarité', definition: "Principe de l'UE selon lequel les décisions doivent être prises au niveau le plus proche des citoyens. L'UE n'intervient que si les objectifs ne peuvent être mieux atteints au niveau national ou local. Protège la souveraineté des États membres face à l'hypertrophie des compétences européennes.", category: 'Union européenne', level: ['Terminale', 'HGGSP'], letter: 'S' },
  { id: 'gl_suffrage_universel', term: 'Suffrage universel', definition: "Droit de vote accordé à tous les citoyens adultes sans distinction de sexe, de race, de fortune ou de religion. En France : suffrage universel masculin (1848), féminin (1944). En Afrique du Sud : universel après la fin de l'apartheid (1994). S'oppose au suffrage censitaire (réservé aux propriétaires).", category: 'Politique', level: ['4e', '3e', 'HGGSP'], letter: 'S' },

  // === T ===
  { id: 'gl_terrorisme', term: 'Terrorisme', definition: "Usage de la violence (attentats, assassinats, prises d'otages) contre des civils à des fins politiques, religieuses ou idéologiques. Vise à répandre la terreur pour contraindre un gouvernement. Les attentats du 11 septembre 2001 (Al-Qaïda) déclenchent la 'guerre contre le terrorisme'. Daech (ISIS) perfectionne la terreur médiatique.", category: 'Sécurité', level: ['3e', 'Terminale', 'HGGSP'], letter: 'T' },
  { id: 'gl_theocracie', term: 'Théocratie', definition: "Régime politique dans lequel le pouvoir est exercé au nom de Dieu et selon les lois religieuses. Exemple : République islamique d'Iran (depuis 1979), Vatican. Les Taliban en Afghanistan (1996-2001, 2021-) appliquent une interprétation rigoriste de la charia.", category: 'Politique', level: ['3e', 'Terminale', 'HGGSP'], letter: 'T' },
  { id: 'gl_tiananmen', term: 'Tiananmen (1989)', definition: "Mouvement pro-démocratie de jeunes Chinois (étudiants, intellectuels) qui occupe la place Tiananmen à Pékin (printemps 1989). Le 4 juin, l'armée chinoise réprime dans le sang (plusieurs centaines à milliers de morts). Cela montre que le Parti Communiste refuse toute démocratisation malgré l'ouverture économique.", category: 'Histoire', level: ['Terminale'], letter: 'T' },
  { id: 'gl_totalitarisme', term: 'Totalitarisme', definition: "Régime politique qui vise à contrôler totalement la société : parti unique, idéologie officielle obligatoire, censure, police politique, culte du chef, embrigadement de la jeunesse. Théorisé par Hannah Arendt (Les origines du totalitarisme, 1951). Exemples : nazisme, stalinisme, fascisme.", category: 'Politique', level: ['3e', '1ere', 'Terminale'], letter: 'T' },
  { id: 'gl_traite_versailles', term: 'Traité de Versailles (1919)', definition: "Traité de paix signé le 28 juin 1919 entre les Alliés et l'Allemagne vaincue. Il impose à l'Allemagne : clause de culpabilité (article 231), réparations (132 milliards de marks-or), pertes territoriales (Alsace-Lorraine à la France), limitation de l'armée. Les Allemands le ressentent comme un 'diktat'. Il contribue à la montée du nazisme.", category: 'Diplomatie', level: ['3e', '1ere'], letter: 'T' },

  // === U ===
  { id: 'gl_ue', term: 'Union européenne (UE)', definition: "Organisation supranationale de 27 États membres (après le Brexit du Royaume-Uni en 2020). Fondée par le traité de Maastricht (1992), elle dispose d'un marché unique, d'une monnaie commune (euro, pour 20 États), d'un Parlement élu et d'une Cour de justice. Elle garantit la libre circulation des personnes, biens, services et capitaux.", category: 'Politique internationale', level: ['3e', 'Terminale', 'HGGSP'], letter: 'U' },
  { id: 'gl_urbanisation', term: 'Urbanisation', definition: "Processus de concentration de la population dans les villes. Au niveau mondial, 56% de la population est urbaine (2020) et ce chiffre devrait atteindre 68% en 2050. En France, l'urbanisation s'accélère pendant la Révolution industrielle (XIXe s.) et les Trente Glorieuses. Elle génère des inégalités territoriales.", category: 'Géographie', level: ['3e', 'Terminale', 'HGGSP'], letter: 'U' },

  // === V ===
  { id: 'gl_velvet_revolution', term: 'Révolutions de velours (1989)', definition: "Terme désignant les transitions pacifiques de l'Europe de l'Est vers la démocratie après la chute du mur de Berlin (novembre 1989). La Tchécoslovaquie (Havel), la Pologne (Solidarnosc), la Hongrie et la Bulgarie se libèrent sans violence. À l'opposé, la Roumanie connaît une révolution violente (mort de Ceaușescu).", category: 'Histoire', level: ['3e', 'Terminale'], letter: 'R' },
  { id: 'gl_veto', term: 'Veto (Conseil de Sécurité)', definition: "Pouvoir accordé aux 5 membres permanents du Conseil de Sécurité de l'ONU (USA, Russie, Chine, France, Royaume-Uni) de bloquer toute résolution. Créé en 1945 pour s'assurer la participation des grandes puissances. La Russie et la Chine l'utilisent fréquemment pour protéger leurs alliés, paralysant parfois l'ONU.", category: 'Relations internationales', level: ['3e', 'Terminale', 'HGGSP'], letter: 'V' },
  { id: 'gl_ve_rep', term: 'Ve République', definition: "Régime politique français depuis 1958, fondé par de Gaulle. Constitution du 4 octobre 1958 : régime semi-présidentiel. Le président de la République est élu au suffrage universel direct (depuis 1962) pour 5 ans (depuis 2000). Il nomme le Premier ministre et dispose de pouvoirs importants (article 16, dissolution, référendum).", category: 'Politique française', level: ['3e', 'Terminale'], letter: 'V' },

  // === W/Y/Z ===
  { id: 'gl_welfare_state', term: 'État Providence (Welfare State)', definition: "Modèle d'État qui assure à tous les citoyens une protection contre les risques sociaux (maladie, chômage, vieillesse, pauvreté) via des assurances et des services publics (Sécurité Sociale, éducation publique). Né en Europe après 1945 (rapport Beveridge en Grande-Bretagne). Remis en question depuis les années 1980 par le néolibéralisme.", category: 'Économie', level: ['3e', 'Terminale', 'HGGSP'], letter: 'E' },
  { id: 'gl_zone_influence', term: "Zone d'influence", definition: "Territoire sur lequel un État exerce une domination politique, économique ou militaire sans en être formellement souverain. La doctrine Monroe (1823) fait des Amériques la sphère d'influence américaine. La Russie revendique un 'étranger proche' post-soviétique. La Chine étend son influence via les Nouvelles Routes de la Soie et les dettes envers les pays africains.", category: 'Géopolitique', level: ['Terminale', 'HGGSP'], letter: 'Z' },

  // === HGGSP — 30 termes ===
  { id: 'gl_acteur_non_etatique', term: 'Acteur non-étatique', definition: "Organisation ou groupe qui joue un rôle dans les relations internationales sans être un État. On distingue : ONG (Greenpeace, MSF), firmes transnationales (Apple, Total), organisations terroristes (Al-Qaïda), médias mondiaux (CNN, Al Jazeera). Ils contestent le monopole étatique sur la scène internationale et complexifient la gouvernance mondiale.", category: 'Relations internationales', level: ['Terminale', 'HGGSP'], letter: 'A' },
  { id: 'gl_agenda_climatique', term: 'Agenda climatique', definition: "Ensemble des engagements et négociations internationales pour lutter contre le changement climatique. Jalons majeurs : Protocole de Kyoto (1997, 1ers engagements contraignants), Accord de Paris (2015, objectif +1,5-2°C), COP26 Glasgow (2021), COP27 Charm el-Cheikh (2022, fonds 'pertes et dommages'). Le financement des pays du Sud est le nœud central des négociations.", category: 'Environnement', level: ['Terminale', 'HGGSP'], letter: 'A' },
  { id: 'gl_basculement_monde', term: 'Basculement du monde', definition: "Expression désignant le déplacement du centre de gravité économique et politique du monde vers l'Asie et les pays émergents depuis les années 2000. La Chine devient la 2e puissance mondiale (PIB en PPA, 2014). L'Asie-Pacifique représente 40% du PIB mondial. Ce basculement remet en cause la domination occidentale héritée du XIXe siècle.", category: 'Géopolitique', level: ['Terminale', 'HGGSP'], letter: 'B' },
  { id: 'gl_choc_civilisations', term: 'Choc des civilisations', definition: "Thèse de Samuel Huntington (1993, 1996) prédisant que les conflits post-Guerre froide opposeraient non plus des idéologies mais des 'civilisations' (occidentale, islamique, confucéenne, orthodoxe). Critiquée comme essentialiste et auto-réalisatrice. Contestée par Edward Said (orientalisme). Thèse remobilisée après le 11 septembre 2001 mais majoritairement réfutée par les chercheurs.", category: 'Géopolitique', level: ['Terminale', 'HGGSP'], letter: 'C' },
  { id: 'gl_cyberguerre', term: 'Cyberguerre', definition: "Ensemble des opérations offensives et défensives menées dans le cyberespace : piratage d'infrastructures, désinformation, sabotage numérique. Les grandes puissances développent des capacités offensives (NSA américaine, unité 61398 chinoise, APT28 russe). Le virus Stuxnet (2010, USA-Israël contre l'Iran) est le premier exemple de cyberarme ciblant des infrastructures physiques réelles.", category: 'Militaire', level: ['Terminale', 'HGGSP'], letter: 'C' },
  { id: 'gl_democratie_illiberale', term: 'Démocratie illibérale', definition: "Régime qui organise des élections régulières (légitimité formelle) mais bafoue les principes libéraux : indépendance de la justice, liberté de la presse, droits des minorités, séparation des pouvoirs. Concept de Fareed Zakaria (1997). Exemples contemporains : Hongrie (Orbán), Turquie (Erdoğan), Russie (Poutine). Correspond souvent à une dérive autoritaire progressive d'une démocratie ancienne.", category: 'Politique', level: ['Terminale', 'HGGSP'], letter: 'D' },
  { id: 'gl_desinformation', term: 'Désinformation', definition: "Diffusion intentionnelle de fausses informations pour tromper l'opinion publique au service d'intérêts politiques. Distincte de la mésinformation (erreur involontaire) et de la malinformation (info vraie utilisée à mauvaise fin). La Russie (RT, Sputnik, fermes à trolls) utilise la désinformation pour déstabiliser les démocraties occidentales. Les réseaux sociaux en amplifient la diffusion.", category: 'Médias', level: ['Terminale', 'HGGSP'], letter: 'D' },
  { id: 'gl_droit_ingerence', term: "Droit d'ingérence humanitaire", definition: "Principe selon lequel la communauté internationale peut intervenir dans un État souverain pour protéger des populations civiles victimes de crimes graves. Théorisé par Mario Bettati et Bernard Kouchner (1987). Codifié par la 'Responsabilité de protéger' (R2P, ONU, 2005). Débattu : ingérence humanitaire vs souveraineté des États. Appliqué en Libye (2011), refusé en Syrie.", category: 'Droit international', level: ['Terminale', 'HGGSP'], letter: 'D' },
  { id: 'gl_etat_failli', term: 'État failli (failed state)', definition: "État qui ne remplit plus ses fonctions essentielles : sécurité du territoire, maintien de l'ordre, fourniture des services de base (eau, santé, éducation), perception des impôts. Exemples : Somalie, Haïti, Libye post-Kadhafi, Yémen. L'effondrement d'un État crée des zones de non-droit propices au terrorisme, aux trafics et aux crises humanitaires.", category: 'Géopolitique', level: ['Terminale', 'HGGSP'], letter: 'E' },
  { id: 'gl_geostrategie', term: 'Géostratégie', definition: "Étude des stratégies militaires et politiques d'un État en fonction de sa géographie : position, frontières, ressources, détroits. Théoriciens fondateurs : Mackinder (théorie du 'Heartland', 1904), Mahan (puissance navale). La géostratégie explique pourquoi certaines zones sont disputées : détroits (Ormuz, Taïwan), mers (Mer de Chine méridionale), ressources (pétrole, terres rares).", category: 'Relations internationales', level: ['Terminale', 'HGGSP'], letter: 'G' },
  { id: 'gl_gouvernance_mondiale', term: 'Gouvernance mondiale', definition: "Ensemble des mécanismes de coordination internationale entre États, organisations internationales, ONG et firmes transnationales pour gérer les problèmes communs (climat, finance, santé, migrations). Ne se confond pas avec un 'gouvernement mondial' inexistant. Institutions clés : ONU, FMI, OMC, G20, OMS. Critiquée pour son déficit démocratique et son inefficacité face aux crises.", category: 'Relations internationales', level: ['Terminale', 'HGGSP'], letter: 'G' },
  { id: 'gl_geopolitique_energie', term: "Géopolitique de l'énergie", definition: "Étude des enjeux de pouvoir liés aux ressources énergétiques (pétrole, gaz, uranium, énergies renouvelables). Le Moyen-Orient concentre 50% des réserves pétrolières mondiales. La Russie utilise le gaz comme levier géopolitique (coupes vers l'Ukraine et l'Europe). La transition vers les renouvelables crée de nouveaux enjeux : terres rares (lithium, cobalt pour les batteries), contrôlées par la Chine.", category: 'Géopolitique', level: ['Terminale', 'HGGSP'], letter: 'G' },
  { id: 'gl_identite_nationale', term: 'Identité nationale', definition: "Sentiment d'appartenance à une nation fondé sur une histoire, une langue, une culture et des symboles communs (drapeau, hymne). Débat : identité exclusive et fermée (nationalisme ethnique) vs identité ouverte et civique (modèle républicain français). L'identité nationale est toujours une construction politique historique, souvent mobilisée par les populismes contre les 'étrangers' et les 'élites'.", category: 'Société', level: ['Terminale', 'HGGSP'], letter: 'I' },
  { id: 'gl_cpi', term: 'CPI (Cour Pénale Internationale)', definition: "Juridiction internationale permanente siégeant à La Haye (fondée en 2002 par le Statut de Rome, 1998). Elle juge les individus accusés de génocide, crimes contre l'humanité et crimes de guerre. 124 États adhérents (USA, Russie, Chine absents). Elle a émis des mandats d'arrêt contre des dirigeants africains et contre Vladimir Poutine (mars 2023). Symbole de la justice universelle.", category: 'Droit international', level: ['Terminale', 'HGGSP'], letter: 'J' },
  { id: 'gl_lobbying', term: 'Lobbying', definition: "Activité consistant à influencer les décisions politiques en faveur d'intérêts privés (industries, ONG, syndicats). Légal et régulé aux USA (K Street à Washington) et à Bruxelles (registre de transparence de l'UE). Peut pervertir la démocratie si opaque. Les lobbies pharmaceutiques, pétroliers et agroalimentaires pèsent considérablement sur les législations climatiques et sanitaires.", category: 'Politique', level: ['Terminale', 'HGGSP'], letter: 'L' },
  { id: 'gl_metropolisation', term: 'Métropolisation', definition: "Concentration croissante des populations, activités économiques et pouvoirs de décision dans les grandes métropoles mondiales. Les 'villes mondiales' (global cities, concept de Saskia Sassen) comme New York, Londres, Tokyo, Shanghai concentrent finance, innovation et culture. Ce phénomène accentue les inégalités territoriales entre métropoles dynamiques et périphéries délaissées.", category: 'Géographie', level: ['Terminale', 'HGGSP'], letter: 'M' },
  { id: 'gl_multilateralisme', term: 'Multilatéralisme', definition: "Mode de coopération internationale impliquant plusieurs États dans le cadre de règles communes et d'institutions partagées (ONU, OMC, OMS, Accords de Paris). Opposé à l'unilatéralisme et au bilatéralisme. Le retrait américain des accords de Paris et de l'OMS sous Trump (2017-2021) a fragilisé le multilatéralisme. La pandémie de Covid-19 a révélé ses limites et sa nécessité.", category: 'Relations internationales', level: ['Terminale', 'HGGSP'], letter: 'M' },
  { id: 'gl_norme_internationale', term: 'Norme internationale', definition: "Règle de conduite acceptée par les États dans le cadre du droit international ou par consensus. Les normes peuvent être contraignantes (traités) ou incitatives (soft law, recommandations). Les grandes puissances cherchent à imposer leurs normes (droits de l'homme, commerce, internet). La Chine promeut un modèle normatif alternatif centré sur la souveraineté numérique et la non-ingérence.", category: 'Droit international', level: ['Terminale', 'HGGSP'], letter: 'N' },
  { id: 'gl_odd', term: 'ODD (Objectifs de Développement Durable)', definition: "Les 17 objectifs adoptés par l'ONU en septembre 2015 dans l'Agenda 2030 : fin de la pauvreté, éducation de qualité, égalité des sexes, énergie propre, action climatique, paix et justice. Successeurs des OMD (2000-2015). Leur réalisation est compromise par les crises successives : Covid-19, guerre en Ukraine, crise de la dette des pays du Sud, accélération du réchauffement.", category: 'Environnement', level: ['Terminale', 'HGGSP'], letter: 'O' },
  { id: 'gl_opinion_publique_mondiale', term: 'Opinion publique mondiale', definition: "Ensemble des attitudes et opinions des populations mondiales sur les grands enjeux internationaux, mesurées par les sondages et révélées par les mobilisations (marches pour le climat, mouvements #MeToo, BLM). Façonnée par les médias mondiaux et les réseaux sociaux. Elle peut peser sur les décisions des gouvernements mais reste inégalement distribuée (pays pauvres sous-représentés).", category: 'Médias', level: ['Terminale', 'HGGSP'], letter: 'O' },
  { id: 'gl_panoptisme', term: 'Panoptisme', definition: "Concept de Michel Foucault (Surveiller et punir, 1975) inspiré du 'panoptique' de Bentham : dispositif où un gardien surveille tous les prisonniers sans être vu, induisant l'auto-surveillance. Métaphore de la surveillance contemporaine : caméras, collecte de données par les GAFAM, scores de crédit social chinois. Les individus se contrôlent eux-mêmes sachant qu'ils peuvent être surveillés.", category: 'Philosophie', level: ['Terminale', 'HGGSP'], letter: 'P' },
  { id: 'gl_puissance_ri', term: 'Puissance (relations internationales)', definition: "Capacité d'un État à influencer les autres et à atteindre ses objectifs sur la scène mondiale. Joseph Nye distingue : hard power (contrainte militaire et économique) et soft power (attraction culturelle et normative). La puissance repose sur des attributs matériels (PIB, armée, démographie) et immatériels (influence, prestige, modèle politique). Le monde post-Guerre froide voit émerger de nouvelles puissances.", category: 'Relations internationales', level: ['Terminale', 'HGGSP'], letter: 'P' },
  { id: 'gl_refugies_climatiques', term: 'Réfugiés climatiques', definition: "Personnes déplacées en raison des effets du changement climatique : montée des eaux, sécheresse, cyclones, désertification. Non reconnus par la Convention de Genève de 1951 (qui ne couvre que les persécutions humaines). De 200 millions à 1 milliard de personnes pourraient être déplacées d'ici 2050. Enjeu géopolitique et humanitaire majeur des prochaines décennies.", category: 'Environnement', level: ['Terminale', 'HGGSP'], letter: 'R' },
  { id: 'gl_raison_etat', term: "Raison d'État", definition: "Doctrine selon laquelle un gouvernement peut transgresser les lois ordinaires ou la morale commune pour préserver l'intérêt supérieur de l'État. Théorisée par Machiavel (Le Prince, 1513) et pratiquée par Richelieu. Justifie : secret d'État, surveillance des citoyens, alliances avec des régimes autoritaires, interventions extérieures non avouées.", category: 'Politique', level: ['Terminale', 'HGGSP'], letter: 'R' },
  { id: 'gl_smart_power', term: 'Smart power', definition: "Combinaison intelligente du hard power (contrainte militaire et économique) et du soft power (influence culturelle et normative). Théorisé par Joseph Nye et Suzanne Nossel. Stratégie prônée par Hillary Clinton pour les États-Unis afin de dépasser le tout-militaire de l'ère Bush. Permet d'optimiser les ressources de politique étrangère en jouant sur plusieurs registres simultanément.", category: 'Relations internationales', level: ['Terminale', 'HGGSP'], letter: 'S' },
  { id: 'gl_societe_civile_int', term: 'Société civile internationale', definition: "Ensemble des ONG, associations, syndicats et mouvements citoyens agissant dans la sphère publique internationale indépendamment des États et des marchés. Elle pèse sur l'agenda politique (présence aux COP, rédaction de traités), documente les violations des droits de l'homme (Amnesty International, Human Rights Watch) et propose des alternatives (alter-mondialisme, commerce équitable).", category: 'Relations internationales', level: ['Terminale', 'HGGSP'], letter: 'S' },
  { id: 'gl_souverainete_numerique', term: 'Souveraineté numérique', definition: "Capacité d'un État ou d'un groupe d'États à contrôler ses données, infrastructures numériques et règles sur internet, sans dépendance à des acteurs étrangers. L'UE développe le RGPD (2018) et l'initiative Cloud européen GAIA-X pour réduire sa dépendance aux GAFAM américains et aux BATX chinois. La Chine a créé son propre internet national (Grande Muraille numérique).", category: 'Médias', level: ['Terminale', 'HGGSP'], letter: 'S' },
  { id: 'gl_transition_energetique', term: 'Transition énergétique', definition: "Passage d'un système énergétique fondé sur les énergies fossiles (pétrole, gaz, charbon) à un mix d'énergies renouvelables (solaire, éolien, hydraulique) et bas-carbone. Nécessaire pour limiter le réchauffement climatique. Elle implique des investissements massifs (milliers de milliards), des mutations industrielles (fin des moteurs thermiques) et de nouveaux enjeux géopolitiques (terres rares pour les batteries).", category: 'Environnement', level: ['Terminale', 'HGGSP'], letter: 'T' },
  { id: 'gl_unilateralisme', term: 'Unilatéralisme', definition: "Politique étrangère d'un État qui agit seul, sans chercher le consensus international ni l'autorisation des institutions multilatérales. Les interventions américaines en Irak (2003, sans mandat ONU) et russes en Ukraine (2022) en sont des exemples. Traduit la puissance d'un État ou son mépris des règles internationales. S'oppose au multilatéralisme défendu par l'ONU.", category: 'Relations internationales', level: ['Terminale', 'HGGSP'], letter: 'U' },

  // === AUTRES NIVEAUX — 21 termes ===
  { id: 'gl_agora', term: 'Agora', definition: "Place publique centrale de la cité grecque, lieu de rassemblement, de débat politique, commercial et religieux. Cœur de la vie démocratique athénienne où les citoyens délibèrent librement. Équivalent romain : le Forum. On y trouve les marchands, les tribunaux populaires, les temples et les stèles de lois. Le terme désigne aujourd'hui tout espace de débat public.", category: 'Politique antique', level: ['6e', '2nde'], letter: 'A' },
  { id: 'gl_traite_negriere', term: 'Traite négrière', definition: "Commerce des esclaves africains organisé par les puissances européennes du XVIe au XIXe siècle. La traite atlantique (commerce triangulaire) déporte 12 à 15 millions d'Africains vers les Amériques. S'y ajoute la traite transsaharienne (vers le monde arabe) et la traite orientale. Reconnue crime contre l'humanité par la loi Taubira (France, 2001). Ses effets économiques, démographiques et psychologiques sur l'Afrique sont durables.", category: 'Histoire coloniale', level: ['4e', '3e', '1ere', 'Terminale'], letter: 'T' },
  { id: 'gl_bioethique', term: 'Bioéthique', definition: "Ensemble des réflexions et règles éthiques portant sur les applications des sciences du vivant sur l'être humain : clonage, avortement, euthanasie, OGM, intelligence artificielle médicale, sélection génétique. Encadrée par des comités d'éthique nationaux (CCNE en France) et la Convention d'Oviedo du Conseil de l'Europe (1997). Enjeu croissant avec les avancées de la biologie.", category: 'Philosophie', level: ['Terminale', '1ere'], letter: 'B' },
  { id: 'gl_commune_paris', term: 'Commune de Paris (1871)', definition: "Gouvernement révolutionnaire qui contrôle Paris du 18 mars au 28 mai 1871 après la défaite de la France face à la Prusse. La Commune instaure des mesures sociales radicales (séparation Église-État, éducation laïque et gratuite, coopératives ouvrières). Écrasée lors de la 'Semaine sanglante' par les troupes versaillaises (20 000-30 000 morts). Mythe fondateur du mouvement ouvrier et socialiste international.", category: 'Histoire française', level: ['4e', '3e'], letter: 'C' },
  { id: 'gl_croisades', term: 'Croisades', definition: "Expéditions militaires organisées par la papauté à partir de 1095 (appel du pape Urbain II à Clermont) pour reprendre Jérusalem et la Terre Sainte aux musulmans. La première croisade (1096-1099) prend Jérusalem. Les croisades créent des États latins d'Orient et favorisent les échanges commerciaux avec l'Orient (épices, soieries, sciences). Huit croisades au total, jusqu'en 1291.", category: 'Religion', level: ['5e', '2nde'], letter: 'C' },
  { id: 'gl_contre_reforme', term: 'Contre-Réforme (Réforme catholique)', definition: "Mouvement de réforme interne de l'Église catholique en réponse au protestantisme (XVIe-XVIIe s.). Le Concile de Trente (1545-1563) réaffirme les dogmes catholiques et réforme le clergé. La Compagnie de Jésus (Jésuites, fondée par Ignace de Loyola, 1540) en est l'instrument missionnaire. Elle reconquiert la Pologne et la Bavière et organise une résistance active au protestantisme.", category: 'Religion', level: ['5e', '2nde'], letter: 'C' },
  { id: 'gl_esclavage_traite', term: 'Esclavage et traite atlantique', definition: "Commerce triangulaire (XVIe-XIXe s.) entre l'Europe (marchandises), l'Afrique (captifs réduits en esclavage) et les Amériques (matières premières). 12 à 15 millions d'Africains sont déportés. L'économie des plantations (sucre, coton, tabac) repose sur ce travail forcé non rémunéré. Aboli en France en 1794, rétabli par Napoléon (1802), définitivement en 1848. Aux États-Unis en 1865 après la guerre de Sécession.", category: 'Histoire coloniale', level: ['4e', '3e'], letter: 'E' },
  { id: 'gl_feodalite', term: 'Féodalité', definition: "Système politique et social médiéval fondé sur des relations de dépendance entre seigneurs et vassaux. Le vassal reçoit un fief (terre avec les paysans) en échange d'un serment de fidélité et de services militaires. La pyramide féodale va du serf au roi en passant par les chevaliers, châtelains et grands seigneurs. Le système s'affaiblit avec la montée des monarchies centralisées (XIVe-XVe s.).", category: 'Histoire', level: ['5e', '4e'], letter: 'F' },
  { id: 'gl_glorieuse_revolution', term: 'Glorieuse Révolution (1688)', definition: "Révolution anglaise sans effusion de sang qui renverse le roi catholique Jacques II et installe Guillaume III d'Orange sur le trône, sous condition d'accepter le Bill of Rights (1689). Ce texte fondamental limite le pouvoir royal et garantit les droits du Parlement et des citoyens. Modèle de la monarchie constitutionnelle, il inspire Locke et, via lui, Montesquieu et les révolutionnaires américains.", category: 'Histoire', level: ['4e', '2nde'], letter: 'G' },
  { id: 'gl_inquisition', term: 'Inquisition', definition: "Tribunal ecclésiastique chargé de détecter et punir les hérétiques menaçant l'unité de l'Église catholique (XIIIe-XIXe s.). L'Inquisition espagnole (1478-1834) persécute juifs convertis (marranes), musulmans convertis (morisques) et protestants. Elle utilise la torture pour obtenir des aveux. Galilée est condamné par l'Inquisition romaine (1633) pour avoir défendu l'héliocentrisme.", category: 'Religion', level: ['5e', '2nde'], letter: 'I' },
  { id: 'gl_jacobins', term: 'Jacobins', definition: "Club politique fondé en 1789, devenu sous Robespierre (1793-1794) le pilier de la Terreur révolutionnaire. Défenseurs d'une République une et indivisible, d'un État centralisé et d'une égalité politique radicale. Le 'jacobinisme' désigne aujourd'hui le centralisme républicain français et l'universalisme contre le fédéralisme et le communautarisme. Robespierre est guillotiné le 9 Thermidor (1794).", category: 'Histoire française', level: ['4e', '3e'], letter: 'J' },
  { id: 'gl_koulaks', term: 'Koulaks', definition: "Paysans aisés (propriétaires d'une exploitation rentable) en Russie. Lors de la collectivisation forcée de Staline (1929-1933), 5 millions de koulaks sont 'dékoulakisés' : déportés au Goulag, exécutés ou abandonnés à la famine. Le terme devient un outil de propagande pour désigner tout paysan résistant à la collectivisation. Exemple emblématique de violence de masse étatique.", category: 'Histoire', level: ['3e', '1ere'], letter: 'K' },
  { id: 'gl_mercantilisme', term: 'Mercantilisme', definition: "Doctrine économique (XVIe-XVIIIe s.) selon laquelle la richesse d'un État se mesure à ses réserves d'or et d'argent. Pour les accumuler : favoriser les exportations, limiter les importations, développer les colonies fournisseuses de matières premières. Colbert applique le mercantilisme en France sous Louis XIV (manufactures royales, Compagnies des Indes). Précurseur du nationalisme économique contemporain.", category: 'Économie', level: ['4e', '2nde'], letter: 'M' },
  { id: 'gl_neolithique', term: 'Néolithique', definition: "Période préhistorique (-10 000 à -3 000 av. J.-C.) marquée par la révolution agricole : sédentarisation des populations, domestication des animaux (chien, bovin, cheval), culture des céréales (blé, orge), invention de la poterie et polissage de la pierre. Cette révolution transforme les sociétés humaines, génère les premiers surplus, les inégalités sociales, les échanges et les proto-États.", category: 'Histoire antique', level: ['6e', '5e'], letter: 'N' },
  { id: 'gl_paleolithique', term: 'Paléolithique', definition: "Première et plus longue période de la Préhistoire (-3 000 000 à -10 000 av. J.-C.) caractérisée par la taille de la pierre. Les hommes vivent en petits groupes nomades de chasseurs-cueilleurs. Grandes étapes : maîtrise du feu (Homo erectus, -400 000), développement du langage, naissance de l'art (grotte de Lascaux, -17 000 ans). Homo sapiens émerge en Afrique orientale vers -300 000.", category: 'Histoire antique', level: ['6e', '5e'], letter: 'P' },
  { id: 'gl_polis', term: 'Polis (cité-État grecque)', definition: "Unité politique de base du monde grec, cité-État souveraine et autonome dotée de ses propres institutions, monnaie, lois et divinités. Chaque polis (il en existe plus de 1 000) est indépendante. Athènes (démocratie) et Sparte (oligarchie militaire) sont les deux modèles antagonistes. La polis fonde le concept occidental de citoyenneté. Alexandre le Grand y met fin en créant son empire.", category: 'Politique antique', level: ['6e', '2nde'], letter: 'P' },
  { id: 'gl_grand_schisme', term: 'Grand Schisme (1054)', definition: "Rupture définitive entre l'Église catholique romaine (pape de Rome) et l'Église orthodoxe (patriarche de Constantinople) en 1054. Causes : désaccords théologiques (Filioque, procession du Saint-Esprit), politiques (primauté du pape) et culturels (latin vs grec). Cette division toujours actuelle détermine les identités religieuses et culturelles de l'Europe (Occident catholique vs Orient orthodoxe).", category: 'Religion', level: ['5e', '2nde'], letter: 'G' },
  { id: 'gl_siecle_pericles', term: 'Siècle de Périclès', definition: "Apogée d'Athènes au Ve siècle av. J.-C. (461-429). Sous la direction de Périclès (stratège élu chaque année), la démocratie s'approfondit (paiement des fonctions publiques permettant la participation des citoyens pauvres), l'empire maritime s'étend via la Ligue de Délos et les arts atteignent leur sommet : Parthénon, tragédies de Sophocle, philosophie de Socrate et Protagoras.", category: 'Histoire antique', level: ['6e', '2nde', 'HGGSP'], letter: 'S' },
  { id: 'gl_tiers_etat', term: 'Tiers État', definition: "Dans la société d'ordres de l'Ancien Régime français, le Tiers État désigne les 97% de la population ne faisant partie ni du clergé (1er ordre) ni de la noblesse (2e ordre). Lors des États généraux de 1789, les représentants du Tiers État se proclament Assemblée nationale (17 juin 1789), acte fondateur de la Révolution française. Sieyès dans sa brochure : 'Qu'est-ce que le Tiers État ? Tout.'", category: 'Histoire française', level: ['4e', '3e'], letter: 'T' },
  { id: 'gl_utopie', term: 'Utopie', definition: "Terme inventé par Thomas More (L'Utopie, 1516, 'u-topos' = 'nulle part' en grec) désignant une société idéale imaginaire. L'utopie est à la fois une critique du présent et un programme politique pour l'avenir. Les utopies socialistes du XIXe s. (Owen, Fourier, Saint-Simon) inspirent le mouvement ouvrier. L'utopie peut se muer en dystopie quand on veut la réaliser par la force (totalitarisme).", category: 'Philosophie', level: ['4e', '2nde', 'HGGSP'], letter: 'U' },
  { id: 'gl_oligarchie', term: 'Oligarchie', definition: "Régime politique dans lequel le pouvoir est exercé par un petit groupe (élite économique, militaire ou familiale). En Grèce antique, l'oligarchie s'oppose à la démocratie : Sparte est gouvernée par un régime oligarchique (deux rois, conseil des anciens). Aujourd'hui désigne les 'oligarques' (milliardaires proches du pouvoir en Russie, Ukraine) ou la capture du processus démocratique par les ultra-riches.", category: 'Politique', level: ['6e', '3e', 'Terminale'], letter: 'O' },
]

export const glossaryData = rawGlossary.map((term) => ({
  ...term,
  category: CATEGORY_MAP[term.category] || 'CULTURAL',
  simpleDefinition: term.definition.split('.')[0] + '.',
  isExamKeyword: ['Terminale', 'HGGSP', '1ere'].some((l) => (term.level || []).includes(l)),
}))

export const glossary = glossaryData
